#!/usr/bin/env bash
# 0-eval-poc-mvp.sh — 从 0 搭起 eval 体系（POC → MVP 之间的前置门） SOP walkthrough for AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同)"
WORKFLOW="从 0 搭起 eval 体系（POC → MVP 之间的前置门）"

usage() {
  cat <<EOF
0-eval-poc-mvp.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./0-eval-poc-mvp.sh             # interactive
  ./0-eval-poc-mvp.sh --dry-run
  ./0-eval-poc-mvp.sh --json
  ./0-eval-poc-mvp.sh --explain
  ./0-eval-poc-mvp.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "从 0 搭起 eval 体系（POC → MVP 之间的前置门）" 工作流。

一句话: 在「认真迭代」开始之前，搭一套能客观回答「这次改动到底有没有让产品变好」的评估基础设施 —— 从「POC 跑通、全凭 vibes」状态到「每次改动都有可回归的度量」状态。这是 AI PM 区别于传统 PM **最硬核**的一段工作。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • Eval 是地基,不是可选项（别 vibe-check）: 「AI 产品的『好』不是看几个 case 觉得行就 ship —— 是先针对你**自己产品的失败模式**建一套可重复、可回归的系统化测量;没有 eval 就是在瞎改。」
  • 先 error analysis,再加功能（PM 亲自看 trace）: 「质量上不去时,资深 AI PM 的第一反应**不是加功能**,是 PM 亲自拉 10-50 个真实 trace（trace 条数量级见 Hamel field-guide T03-S001 / ev

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**PM 亲自看 trace 做 error analysis**：阻塞 30 分钟，拉 10-20 个真实交互，逐条记「哪里对了、哪里错了」的开放式笔记。**PM 主导**（PM 是首席领域专家，这一步不能外包给工程师）。跳过 → 后面所有 eval 指标都是凭空想的、测不到真问题。 (evidence: [T03-S001, T03-S006, T03-S008])"
  "**自下而上归类成 failure mode**：让笔记里的 pattern 自然涌现，用 LLM 把笔记聚成 taxonomy，数每类频率。PM 主导。跳过 → 直接上「helpfulness / hallucination 通用 dashboard」，测的是噪声不是你的产品。 (evidence: [T03-S001, T03-S006])"
  "**建 golden set**：针对 top failure mode，PM + 领域专家共同确认 30-50 个「系统最该正确处理」的用例。合成数据按 features × scenarios × personas 三维度造，ground 在真实约束上。PM + 领域专家。跳过 → 没有回归基线，改 A 修好了不知道有没有弄坏 B。 (evidence: [T03-S001, T03-S016])"
  "**先建最便宜的 code-based check**：能用 regex / 结构校验 / 执行测试确定性判断的，绝不先上 LLM-judge。PM 提需求，工程师实现。跳过 → 一上来烧钱建 LLM-judge 评一个正则就能评的东西。 (evidence: [T03-S006])"
  "**建 LLM-as-judge 并和人工校准**：用 rubric 把 judge 和人工标注对齐到 75-90% 一致再 scale；用 binary pass/fail 不用 1-5 分。PM 定 rubric + 标注，工程师建 scorer。跳过 → 一个没校准的 judge 给的分等于没用，团队很快不信它。 (evidence: [T03-S007, T03-S016, T03-S008])"
  "**接上 offline + online 两层**：offline 作迭代默认引擎，online 对真实流量做 reality check（shadow / canary）。PM 定 online 指标，工程师接 production 数据管线。跳过 → 只有 offline 会过拟合 golden set；只有 online 改动反馈太慢。 (evidence: [T03-S012, T03-S013])"
)
declare -a FAILURE_MODES=(
  "**跳过 error analysis 直接上指标 dashboard**：触发原因 = dashboard 看着专业、error analysis 像「手工活」；怎么避免 = 强制 PM 先花 30 分钟看 10-20 条 trace 再说。（**CLI 自检项**：Did you build a metrics dashboard before reading 20 real traces by hand? If yes — the dashboard is measuring noise, not your product.） (evidence: [T03-S001, T03-S006])"
  "**LLM-judge 没校准就 scale**：触发原因 = 「让 GPT 打分」看着就能用；怎么避免 = 上线前必须验 judge 和人工标注 75-90% 一致。（**CLI 自检项**：Has your LLM-judge been calibrated against human labels to 75-90% agreement? An uncalibrated judge is worse than no judge — the team will stop trusting it.） (evidence: [T03-S007, T03-S016])"
  "**过早把 eval 工具外包 / 过早全自动化**：触发原因 = vendor 营销「我们的 pre-built judge 开箱即用」；怎么避免 = 校准必须针对你自己的数据，早期保持高人工参与度。（**CLI 自检项**：Are you relying on a vendor's pre-built judge without validating it on your own data? Calibration is domain-specific — it can't be outsourced.） (evidence: [T03-S001, T03-S007])"
  "**golden set 太大 / 当成训练数据**：触发原因 = 外行「数据越多越好」直觉；怎么避免 = golden set 小而精（30-50 个），是评估用不是训练用。（**CLI 自检项**：Is your golden set hundreds of examples or being used to train? Keep it 30-50, expert-curated, eval-only.） (evidence: [T03-S016])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "0-eval-poc-mvp-walkthrough"
fi
